using Microsoft.EntityFrameworkCore;
class ProductContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Product>(entity =>
        {
            entity.ToContainer("Products");

            // BREAKING CHANGE 1: EF Core 9 renamed "Discriminator" to "$type".
            // Existing 500K documents use "Discriminator", so we must preserve it.
            entity.HasDiscriminator<string>("Discriminator");

            // BREAKING CHANGE 2: EF Core 9 uses simplified ID format (just "123")
            // instead of "Product|123". Preserve the legacy format for existing data.
            entity.HasKey(p => p.Id);
            entity.Property(p => p.Id)
                .ToJsonProperty("id")
                .HasValueGenerator<LegacyCosmosIdGenerator>();

            // BREAKING CHANGE 3: EF Core 9 removed sync I/O support for Cosmos.
            // All queries must use async (ToListAsync, etc.). See CosmosQuery.cs.

            entity.HasIndex(p => p.Sku);
        });
    }
}

class Product
{
    public int Id { get; set; }
    public string Sku { get; set; }
}

